import React, { useMemo, useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import AddProject from './AddProject'; // Adjust the import path as needed
import EditProject from './EditProject'; // Adjust the import path as needed
import './PurchaseFunc.css'; // Ensure this path matches your CSS file's location

const ProjectFunc = ({ apiBaseUrl }) => {
  const [editingProject, setEditingProject] = useState(null);
  const [projects, setProjects] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [filterInput, setFilterInput] = useState(''); // Renamed for clarity

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  const fetchData = useCallback(async () => {
    try {
      const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
      setProjects(projectsResponse);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setIsLoading(false);
    }
  }, [fetchAPI, apiBaseUrl]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddProject = useCallback(async (newProject) => {
    try {
      await fetchAPI(`${apiBaseUrl}/projectsAPI`, {
        method: 'POST',
        body: JSON.stringify(newProject),
      });
      fetchData();
    } catch (error) {
      console.error('Error adding project:', error);
    }
  }, [fetchData, fetchAPI, apiBaseUrl]);

  const handleDelete = useCallback(async (projectID) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      try {
        await fetchAPI(`${apiBaseUrl}/projectsAPI/${projectID}`, {
          method: 'DELETE',
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting project:', error);
      }
    }
  }, [fetchData, fetchAPI, apiBaseUrl]);

  const handleEdit = useCallback((project) => {
    setEditingProject(project);
  }, []);

  const handleUpdateProject = useCallback(async (updatedProject) => {
    try {
      await fetchAPI(`${apiBaseUrl}/projectsAPI/${updatedProject.id}`, {
        method: 'PUT',
        body: JSON.stringify(updatedProject),
      });
      fetchData();
    } catch (error) {
      console.error('Error updating project:', error);
    } finally {
      setEditingProject(null);
    }
  }, [fetchData, fetchAPI, apiBaseUrl]);

  const handleCancelEdit = useCallback(() => {
    setEditingProject(null);
  }, []);

  const columns = useMemo(() => [
    { Header: 'ID', accessor: 'id' },
    { Header: 'Name', accessor: 'name' },
    { Header: 'Description', accessor: 'description' },
    { Header: 'Status', accessor: 'status' },
    { Header: 'Actions', accessor: 'actions', Cell: ({ row }) => (
        <div>
          <button onClick={() => handleEdit(row.original)}>Edit</button>
          <button onClick={() => handleDelete(row.original.id)}>Delete</button>
        </div>
      ),
    },
  ], [handleEdit, handleDelete]);

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    prepareRow,
    setGlobalFilter,
    rows,
  } = useTable(
    {
      columns,
      data: projects,
      initialState: { pageIndex: 0 },
    },
    useGlobalFilter, // Use the useGlobalFilter plugin hook
    useSortBy,
    usePagination
  );

  // Set global filter effect
  useEffect(() => {
    setGlobalFilter(filterInput || undefined);
  }, [filterInput, setGlobalFilter]);

  if (isLoading) return <div>Loading...</div>;

  return (
    <div className="container">
      <AddProject handleAddProject={handleAddProject} />
      <input
        value={filterInput}
        onChange={e => setFilterInput(e.target.value)}
        placeholder="Search projects..."
      />
      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map(headerGroup => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map(column => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map(row => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map(cell => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
      {editingProject && (
        <EditProject
          project={editingProject}
          handleUpdate={handleUpdateProject}
          handleCancel={handleCancelEdit}
        />
      )}
    </div>
  );
};

export default ProjectFunc;
